import React, { useEffect } from 'react';
import { Link } from 'react-router-dom';
import { projectsData } from '../../constants/projectData';
import styles from './Projects.module.css';
import { FaArrowRight, FaCheckCircle, FaBriefcase } from 'react-icons/fa';
import { updateSeo } from '../../utils/seoHelper';

function Projects() {
  useEffect(() => {
    updateSeo({
      title: 'Our Projects - Kognivex',
      description: 'Explore our portfolio of real-world business solutions. From E-commerce to Healthcare, see how Kognivex builds scalable digital products.',
    });
  }, []);

  return (
    <main className={styles.projectsPage}>
      <div className={styles.container}>
        <header className={styles.header}>
          <div className={styles.badge}>Our Portfolio</div>
          <h1>Engineering Real-World <span>Solutions</span></h1>
          <p>
            We don't just build websites; we solve complex business problems. 
            Explore our diverse portfolio of scalable digital products designed for growth and impact.
          </p>
        </header>

        <div className={styles.grid}>
          {projectsData.map((project) => (
            <article key={project.id} className={styles.projectCard}>
              <div className={styles.imageWrapper}>
                <img src={project.image} alt={project.title} loading="lazy" />
                <div className={styles.industryTag}>
                  <FaBriefcase size={12} /> {project.industry}
                </div>
              </div>

              <div className={styles.content}>
                <h3>{project.title}</h3>
                <p className={styles.description}>{project.description}</p>

                <div className={styles.featuresSection}>
                  <h4>Key Features:</h4>
                  <ul className={styles.featuresList}>
                    {project.features.map((feature, index) => (
                      <li key={index}>
                        <FaCheckCircle className={styles.checkIcon} /> {feature}
                      </li>
                    ))}
                  </ul>
                </div>

                <div className={styles.cardFooter}>
                  <Link to={`/projects/${project.slug}`} className={styles.viewBtn}>
                    Case Study <FaArrowRight />
                  </Link>
                </div>
              </div>
            </article>
          ))}
        </div>
      </div>

      <section className={styles.ctaSection}>
        <div className={styles.container}>
          <h2>Have a Project in Mind?</h2>
          <p>Let's turn your business vision into a scalable digital reality.</p>
          <Link to="/contact" className={styles.primaryBtn}>Start a Conversation</Link>
        </div>
      </section>
    </main>
  );
}

export default Projects;
